import{_ as a,o as e,c as d,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse(`{"title":"喜诗糖果（See's Candies）","description":"","frontmatter":{},"headers":[],"relativePath":"03_companies/喜诗糖果.md","filePath":"03_companies/喜诗糖果.md"}`),l={name:"03_companies/喜诗糖果.md"};function i(h,t,o,n,s,u){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="喜诗糖果-see-s-candies" tabindex="-1">喜诗糖果（See&#39;s Candies） <a class="header-anchor" href="#喜诗糖果-see-s-candies" aria-label="Permalink to &quot;喜诗糖果（See&#39;s Candies）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>See&#39;s Candies</td></tr><tr><td>行业</td><td>食品/糖果零售</td></tr><tr><td>成立年份</td><td>1921年</td></tr><tr><td>总部</td><td>加利福尼亚州旧金山</td></tr><tr><td>伯克希尔持股</td><td>100%（通过蓝筹印花收购）</td></tr><tr><td>收购价格</td><td>2,500万美元（1972年）</td></tr></tbody></table><h2 id="核心业务" tabindex="-1">核心业务 <a class="header-anchor" href="#核心业务" aria-label="Permalink to &quot;核心业务&quot;">​</a></h2><p>高品质盒装巧克力制造与零售，在美国西部拥有约200家零售店。圣诞季是销售高峰，前四周占全年销量40%，利润75%。</p><h2 id="收购故事" tabindex="-1">收购故事 <a class="header-anchor" href="#收购故事" aria-label="Permalink to &quot;收购故事&quot;">​</a></h2><h3 id="收购背景" tabindex="-1">收购背景 <a class="header-anchor" href="#收购背景" aria-label="Permalink to &quot;收购背景&quot;">​</a></h3><ul><li><strong>1972年</strong>：蓝筹印花（伯克希尔控股约60%）以2,500万美元收购</li><li>收购时有形净资产约800万美元，税后盈利约200万美元</li><li>ROE约25%，拥有强大的消费者特许权</li></ul><h3 id="收购逻辑" tabindex="-1">收购逻辑 <a class="header-anchor" href="#收购逻辑" aria-label="Permalink to &quot;收购逻辑&quot;">​</a></h3><ol><li><strong>品牌价值</strong>：加州老牌，消费者忠诚度高</li><li><strong>无需大量资本投入</strong>：业务增长不需重资产投入</li><li><strong>定价权</strong>：可随通胀提价，销量不受影响</li><li><strong>现金流优异</strong>：盈利可全部转化为现金</li></ol><h2 id="核心竞争优势" tabindex="-1">核心竞争优势 <a class="header-anchor" href="#核心竞争优势" aria-label="Permalink to &quot;核心竞争优势&quot;">​</a></h2><h3 id="_1-消费者特许权" tabindex="-1">1. 消费者特许权 <a class="header-anchor" href="#_1-消费者特许权" aria-label="Permalink to &quot;1. 消费者特许权&quot;">​</a></h3><ul><li>产品质量口碑卓越</li><li>节日送礼首选品牌</li><li>高客户忠诚度</li></ul><h3 id="_2-经济商誉价值" tabindex="-1">2. 经济商誉价值 <a class="header-anchor" href="#_2-经济商誉价值" aria-label="Permalink to &quot;2. 经济商誉价值&quot;">​</a></h3><ul><li>1972年收购时账面价值800万美元</li><li>盈利能力却相当于账面值数倍</li><li>经典案例：经济商誉vs会计商誉（见1983年股东信附录）</li></ul><h3 id="_3-资本效率" tabindex="-1">3. 资本效率 <a class="header-anchor" href="#_3-资本效率" aria-label="Permalink to &quot;3. 资本效率&quot;">​</a></h3><ul><li>增长不需追加大量资本</li><li>盈利可全部返还母公司</li><li>伯克希尔可用这些现金投资其他机会</li></ul><h2 id="管理团队" tabindex="-1">管理团队 <a class="header-anchor" href="#管理团队" aria-label="Permalink to &quot;管理团队&quot;">​</a></h2><h3 id="关键人物" tabindex="-1">关键人物 <a class="header-anchor" href="#关键人物" aria-label="Permalink to &quot;关键人物&quot;">​</a></h3><table tabindex="0"><thead><tr><th>姓名</th><th>职位</th><th>贡献</th></tr></thead><tbody><tr><td><a href="./../04_人物库/Chuck_Huggins">Chuck Huggins</a></td><td>总经理</td><td>1972年起管理，表现非凡</td></tr><tr><td>Mary See</td><td>创始人</td><td>1921年创立配方</td></tr></tbody></table><h3 id="管理特点" tabindex="-1">管理特点 <a class="header-anchor" href="#管理特点" aria-label="Permalink to &quot;管理特点&quot;">​</a></h3><ul><li>保持客户导向企业文化</li><li>产品质量绝不妥协</li><li>服务质量行业领先</li></ul><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><blockquote><p>&quot;喜诗糖果拥有非常有价值的消费者特许权。&quot; —— 1981年股东信</p></blockquote><blockquote><p>&quot;在约2,000万净有形资产上，喜诗能税后赚1,300万美元。&quot; —— 1981年股东信</p></blockquote><blockquote><p>&quot;经济商誉让企业在有形净资产上获得超额回报。喜诗是典型案例。&quot; —— 1983年股东信附录</p></blockquote><h2 id="财务表现-摘录" tabindex="-1">财务表现（摘录） <a class="header-anchor" href="#财务表现-摘录" aria-label="Permalink to &quot;财务表现（摘录）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>销售额</th><th>税前利润</th><th>备注</th></tr></thead><tbody><tr><td>1972（收购年）</td><td>-</td><td>200万美元（税后）</td><td>有形净资产800万</td></tr><tr><td>1981</td><td>-</td><td>2,189万美元</td><td>税前</td></tr><tr><td>1982</td><td>-</td><td>2,388万美元</td><td>税前</td></tr><tr><td>1984</td><td>1.36亿美元</td><td>1,338万美元（税后）</td><td>圣诞季占利润75%</td></tr></tbody></table><h2 id="季节性特征" tabindex="-1">季节性特征 <a class="header-anchor" href="#季节性特征" aria-label="Permalink to &quot;季节性特征&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时期</th><th>销量占比</th><th>利润占比</th></tr></thead><tbody><tr><td>圣诞前四周</td><td>40%</td><td>75%</td></tr><tr><td>其他时段</td><td>60%</td><td>25%</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1977, 1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./内布拉斯加家具城">内布拉斯加家具城</a> - 同为经典收购案例</li><li><a href="./蓝筹印花">蓝筹印花</a> - 收购主体</li><li><a href="./../02_主题索引/投资哲学/商誉经济学">经济商誉论</a> - 1983年附录</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',36)])])}const q=a(l,[["render",i]]);export{c as __pageData,q as default};
